16→internal class RealDrawerConfigManager(
17→    private val preferences: Preferences,
18→    private val coroutineScope: CoroutineScope,
19→    private val changeBroker: SettingsChangeBroker,
20→) : DrawerConfigManager {
21→    private val drawerConfigFlow = MutableSharedFlow<DrawerConfig>(replay = 1)
22→
23→    init {
24→        coroutineScope.launch {
25→            asSettingsFlow().collect { config ->
26→                drawerConfigFlow.emit(config)
27→            }
28→        }
29→    }
30→
31→    override fun save(config: DrawerConfig) {
32→        saveDrawerConfig(config)
33→        updateDrawerConfigFlow(config)
34→    }
35→
36→    private fun loadDrawerConfig(): DrawerConfig {
37→        return DrawerConfig(
38→            showAccountSelector = K9.isShowAccountSelector,
39→            showStarredCount = K9.isShowStarredCount,
40→            showUnifiedFolders = K9.isShowUnifiedInbox,
41→        )
42→    }
43→
44→    private fun updateDrawerConfigFlow(config: DrawerConfig) {
45→        coroutineScope.launch {
46→            drawerConfigFlow.emit(config)
47→        }
48→    }
49→
50→    @Synchronized
51→    override fun getConfig(): DrawerConfig {
52→        return loadDrawerConfig().also {
53→            updateDrawerConfigFlow(it)
54→        }
55→    }
56→
57→    override fun getConfigFlow(): Flow<DrawerConfig> {
58→        return drawerConfigFlow.distinctUntilChanged()
59→    }
60→
61→    private fun asSettingsFlow(): Flow<DrawerConfig> {
62→        return callbackFlow {
63→            send(loadDrawerConfig())
64→
65→            val subscriber = SettingsChangeSubscriber {
66→                drawerConfigFlow.tryEmit(loadDrawerConfig())
67→            }
68→
69→            changeBroker.subscribe(subscriber)
70→
71→            awaitClose {
72→                changeBroker.unsubscribe(subscriber)
73→            }
74→        }
75→    }
76→
77→    @Synchronized
78→    private fun saveDrawerConfig(config: DrawerConfig) {
79→        val editor = preferences.createStorageEditor()
80→        K9.save(editor)
81→        writeDrawerConfig(editor, config)
82→        editor.commit()
83→    }
84→
85→    private fun writeDrawerConfig(editor: StorageEditor, config: DrawerConfig) {
86→        editor.putBoolean("showAccountSelector", config.showAccountSelector)
87→        editor.putBoolean("showUnifiedInbox", config.showUnifiedFolders)
88→        editor.putBoolean("showStarredCount", config.showStarredCount)
89→    }
90→}
