  5→import java.util.Map;
  6→
  7→import android.content.Context;
  8→import android.database.Cursor;
  9→import android.database.sqlite.SQLiteDatabase;
 10→import android.database.sqlite.SQLiteStatement;
 11→import android.os.SystemClock;
 12→
 13→import androidx.annotation.NonNull;
 14→import com.fsck.k9.helper.Utility;
 15→import com.fsck.k9.preferences.migration.DefaultStorageMigrationHelper;
 16→import com.fsck.k9.preferences.migration.StorageMigrations;
 17→import com.fsck.k9.preferences.migration.StorageMigrationHelper;
 18→import timber.log.Timber;
 19→
 20→
 21→public class K9StoragePersister implements StoragePersister {
 22→    private static final int DB_VERSION = 26;
 23→    private static final String DB_NAME = "preferences_storage";
 24→
 25→    private final Context context;
 26→    private final StorageMigrationHelper migrationHelper = new DefaultStorageMigrationHelper();
 27→
 28→    public K9StoragePersister(Context context) {
 29→        this.context = context;
 30→    }
 31→
 32→    private SQLiteDatabase openDB() {
 33→        SQLiteDatabase db = context.openOrCreateDatabase(DB_NAME, Context.MODE_PRIVATE, null);
 34→
 35→        db.beginTransaction();
 36→        try {
 37→            if (db.getVersion() > DB_VERSION) {
 38→                throw new AssertionError("Database downgrades are not supported. " +
 39→                        "Please fix the database '" + DB_NAME + "' manually or clear app data.");
 40→            }
 41→
 42→            if (db.getVersion() < 1) {
 43→                createStorageDatabase(db);
 44→            } else {
 45→                StorageMigrations.upgradeDatabase(db, migrationHelper);
 46→            }
 47→
 48→            db.setVersion(DB_VERSION);
 49→            db.setTransactionSuccessful();
 50→        } finally {
 51→            db.endTransaction();
 52→        }
 53→
 54→        if (db.getVersion() != DB_VERSION) {
 55→            throw new RuntimeException("Storage database upgrade failed!");
 56→        }
 57→
 58→        return db;
 59→    }
 60→
 61→    private void createStorageDatabase(SQLiteDatabase db) {
 62→        Timber.i("Creating Storage database");
 63→
 64→        db.execSQL("DROP TABLE IF EXISTS preferences_storage");
 65→        db.execSQL("CREATE TABLE preferences_storage " +
 66→                "(primkey TEXT PRIMARY KEY ON CONFLICT REPLACE, value TEXT)");
 67→        db.setVersion(DB_VERSION);
 68→    }
 69→
 70→    void doInTransaction(StoragePersistOperationCallback operationCallback) {
 71→        HashMap<String, String> workingStorage = new HashMap<>();
 72→        SQLiteDatabase workingDb = openDB();
 73→
 74→        try {
 75→            operationCallback.beforePersistTransaction(workingStorage);
 76→
 77→            StoragePersistOperations storagePersistOperations = new StoragePersistOperations(workingStorage, workingDb);
 78→            workingDb.beginTransaction();
 79→            operationCallback.persist(storagePersistOperations);
 80→            storagePersistOperations.close();
 81→            workingDb.setTransactionSuccessful();
 82→
 83→            operationCallback.onPersistTransactionSuccess(workingStorage);
 84→        } finally {
 85→            workingDb.endTransaction();
 86→            workingDb.close();
 87→        }
 88→    }
 89→
 90→    @NonNull
 91→    @Override
 92→    public StorageEditor createStorageEditor(@NonNull StorageUpdater storageUpdater) {
 93→        return new K9StorageEditor(storageUpdater, this);
 94→    }
 95→
 96→    static class StoragePersistOperations {
 97→        private Map<String, String> workingStorage;
 98→        private final SQLiteStatement deleteStatement;
 99→        private final SQLiteStatement insertStatement;
100→
101→        private StoragePersistOperations(Map<String, String> workingStorage, SQLiteDatabase database) {
102→            this.workingStorage = workingStorage;
103→
104→            insertStatement = database.compileStatement(
105→                    "INSERT INTO preferences_storage (primkey, value) VALUES (?, ?)");
106→            deleteStatement = database.compileStatement(
107→                    "DELETE FROM preferences_storage WHERE primkey = ?");
108→        }
109→
110→        void put(String key, String value) {
111→            insertStatement.bindString(1, key);
112→            insertStatement.bindString(2, value);
113→            insertStatement.execute();
114→            insertStatement.clearBindings();
115→
116→            workingStorage.put(key, value);
117→        }
118→
119→        void remove(String key) {
120→            deleteStatement.bindString(1, key);
121→            deleteStatement.executeUpdateDelete();
122→            deleteStatement.clearBindings();
123→
124→            workingStorage.remove(key);
125→        }
126→
127→        private void close() {
128→            insertStatement.close();
129→            deleteStatement.close();
130→        }
131→    }
132→
133→    interface StoragePersistOperationCallback {
134→        void beforePersistTransaction(Map<String, String> workingStorage);
135→        void persist(StoragePersistOperations ops);
136→        void onPersistTransactionSuccess(Map<String, String> workingStorage);
137→    }
138→
139→    @NonNull
140→    @Override
141→    public Storage loadValues() {
142→        long startTime = SystemClock.elapsedRealtime();
143→        Timber.i("Loading preferences from DB into Storage");
144→
145→        try (SQLiteDatabase database = openDB()) {
146→            return new Storage(readAllValues(database));
147→        } finally {
148→            long endTime = SystemClock.elapsedRealtime();
149→            Timber.i("Preferences load took %d ms", endTime - startTime);
150→        }
151→    }
152→
153→    private Map<String, String> readAllValues(SQLiteDatabase database) {
154→        HashMap<String, String> loadedValues = new HashMap<>();
155→        Cursor cursor = null;
156→        try {
157→            cursor = database.rawQuery("SELECT primkey, value FROM preferences_storage", null);
158→            while (cursor.moveToNext()) {
159→                String key = cursor.getString(0);
160→                String value = cursor.getString(1);
161→                Timber.d("Loading key '%s', value = '%s'", key, value);
162→                loadedValues.put(key, value);
163→            }
164→        } finally {
165→            Utility.closeQuietly(cursor);
166→        }
167→
168→        return loadedValues;
169→    }
170→}
